/**
 * Schema Audit Engine
 *
 * Pure-function engine for auditing Prisma schema files.
 * Detects: naming convention violations, missing indices, fields without defaults,
 * migration drift indicators, and generates structured audit reports.
 *
 * @module schema-audit
 */

// ─── Types ───────────────────────────────────────────────────────────

export type Severity = 'error' | 'warning' | 'info';

export interface SchemaField {
  name: string;
  type: string;
  isOptional: boolean;
  hasDefault: boolean;
  hasMap: boolean;
  mapValue: string | null;
  dbType: string | null;
  isId: boolean;
  isUnique: boolean;
  isRelation: boolean;
  rawLine: string;
}

export interface SchemaIndex {
  fields: string[];
  name: string | null;
  isUnique: boolean;
}

export interface SchemaModel {
  name: string;
  schema: string;
  fields: SchemaField[];
  indices: SchemaIndex[];
  hasCreatedAt: boolean;
  hasUpdatedAt: boolean;
  lineNumber: number;
}

export interface SchemaEnum {
  name: string;
  values: string[];
  schema: string;
  lineNumber: number;
}

export interface AuditIssue {
  severity: Severity;
  category: string;
  model: string;
  field: string | null;
  message: string;
  suggestion: string;
}

export interface AuditSummary {
  totalModels: number;
  totalFields: number;
  totalEnums: number;
  totalIndices: number;
  totalIssues: number;
  errorCount: number;
  warningCount: number;
  infoCount: number;
  schemas: string[];
  modelsWithoutTimestamps: string[];
  modelsWithoutIndices: string[];
  namingViolations: number;
}

export interface AuditReport {
  generatedAt: string;
  schemaFile: string;
  summary: AuditSummary;
  issues: AuditIssue[];
  models: SchemaModel[];
  enums: SchemaEnum[];
}

// ─── Parsing ─────────────────────────────────────────────────────────

/**
 * Parse a single field line from a Prisma schema model.
 */
export function parseFieldLine(line: string): SchemaField | null {
  const trimmed = line.trim();
  if (!trimmed || trimmed.startsWith('//') || trimmed.startsWith('///')) return null;
  if (trimmed.startsWith('@@')) return null;
  if (trimmed === '{' || trimmed === '}') return null;

  // Match: fieldName Type? @attributes...
  const fieldMatch = trimmed.match(/^(\w+)\s+(\w+)(\??)\s*(.*)?$/);
  if (!fieldMatch) return null;

  const [, name, type, optMarker, rest] = fieldMatch;
  const attrs = rest || '';

  // Skip relation fields (capitalized types without @db)
  const isRelation = /^[A-Z]/.test(type) && !attrs.includes('@db.');

  const mapMatch = attrs.match(/@map\("([^"]+)"\)/);
  const dbTypeMatch = attrs.match(/@db\.(\w+)/);

  return {
    name,
    type,
    isOptional: optMarker === '?',
    hasDefault: attrs.includes('@default'),
    hasMap: mapMatch !== null,
    mapValue: mapMatch ? mapMatch[1] : null,
    dbType: dbTypeMatch ? dbTypeMatch[1] : null,
    isId: attrs.includes('@id'),
    isUnique: attrs.includes('@unique'),
    isRelation,
    rawLine: trimmed,
  };
}

/**
 * Parse index/unique directives from model body lines.
 */
export function parseIndexLine(line: string): SchemaIndex | null {
  const trimmed = line.trim();

  const indexMatch = trimmed.match(/@@(index|unique)\(\[([^\]]+)\](?:,\s*map:\s*"([^"]+)")?\)/);
  if (!indexMatch) return null;

  const [, directive, fieldsStr, mapName] = indexMatch;
  const fields = fieldsStr.split(',').map((f) => f.trim());

  return {
    fields,
    name: mapName || null,
    isUnique: directive === 'unique',
  };
}

/**
 * Extract the @@schema("...") value from model body lines.
 */
export function extractSchema(lines: string[]): string {
  for (const line of lines) {
    const match = line.match(/@@schema\("([^"]+)"\)/);
    if (match) return match[1];
  }
  return 'public';
}

/**
 * Parse full Prisma schema content into structured models and enums.
 */
export function parseSchema(content: string): { models: SchemaModel[]; enums: SchemaEnum[] } {
  const lines = content.split('\n');
  const models: SchemaModel[] = [];
  const enums: SchemaEnum[] = [];

  let i = 0;
  while (i < lines.length) {
    const line = lines[i];
    const trimmed = line.trim();

    // Match model declaration
    const modelMatch = trimmed.match(/^model\s+(\w+)\s*\{$/);
    if (modelMatch) {
      const modelName = modelMatch[1];
      const modelLineNumber = i + 1;
      const bodyLines: string[] = [];
      i++;
      let braceCount = 1;
      while (i < lines.length && braceCount > 0) {
        const bodyLine = lines[i];
        if (bodyLine.includes('{')) braceCount++;
        if (bodyLine.includes('}')) braceCount--;
        if (braceCount > 0) bodyLines.push(bodyLine);
        i++;
      }

      const fields: SchemaField[] = [];
      const indices: SchemaIndex[] = [];
      for (const bl of bodyLines) {
        const field = parseFieldLine(bl);
        if (field) fields.push(field);
        const idx = parseIndexLine(bl);
        if (idx) indices.push(idx);
      }

      const schema = extractSchema(bodyLines);
      const hasCreatedAt = fields.some((f) => f.name === 'createdAt' || f.name === 'created_at');
      const hasUpdatedAt = fields.some((f) => f.name === 'updatedAt' || f.name === 'updated_at');

      models.push({
        name: modelName,
        schema,
        fields,
        indices,
        hasCreatedAt,
        hasUpdatedAt,
        lineNumber: modelLineNumber,
      });
      continue;
    }

    // Match enum declaration
    const enumMatch = trimmed.match(/^enum\s+(\w+)\s*\{$/);
    if (enumMatch) {
      const enumName = enumMatch[1];
      const enumLineNumber = i + 1;
      const enumBodyLines: string[] = [];
      i++;
      let braceCount = 1;
      while (i < lines.length && braceCount > 0) {
        const bodyLine = lines[i];
        if (bodyLine.includes('{')) braceCount++;
        if (bodyLine.includes('}')) braceCount--;
        if (braceCount > 0) enumBodyLines.push(bodyLine);
        i++;
      }

      const values: string[] = [];
      for (const bl of enumBodyLines) {
        const valueLine = bl.trim();
        if (valueLine && !valueLine.startsWith('//') && !valueLine.startsWith('@@')) {
          const valueMatch = valueLine.match(/^(\w+)/);
          if (valueMatch) values.push(valueMatch[1]);
        }
      }

      const schema = extractSchema(enumBodyLines);
      enums.push({ name: enumName, values, schema, lineNumber: enumLineNumber });
      continue;
    }

    i++;
  }

  return { models, enums };
}

// ─── Naming Convention Checks ────────────────────────────────────────

/**
 * Check if a string is camelCase.
 */
export function isCamelCase(s: string): boolean {
  return /^[a-z][a-zA-Z0-9]*$/.test(s);
}

/**
 * Check if a string is snake_case.
 */
export function isSnakeCase(s: string): boolean {
  return /^[a-z][a-z0-9]*(_[a-z0-9]+)*$/.test(s);
}

/**
 * Check if a string is PascalCase.
 */
export function isPascalCase(s: string): boolean {
  return /^[A-Z][a-zA-Z0-9]*$/.test(s);
}

/**
 * Convert camelCase to snake_case for expected @map value.
 */
export function camelToSnake(s: string): string {
  return s.replace(/([A-Z])/g, '_$1').toLowerCase();
}

/**
 * Validate naming conventions for a field.
 * Prisma convention: camelCase field names, @map("snake_case") for DB column.
 */
export function checkFieldNaming(model: string, field: SchemaField): AuditIssue | null {
  // Skip relation fields and IDs
  if (field.isRelation || field.name === 'id') return null;

  // Field name should be camelCase in Prisma
  if (!isCamelCase(field.name) && !isSnakeCase(field.name)) {
    return {
      severity: 'warning',
      category: 'naming',
      model,
      field: field.name,
      message: `Field "${field.name}" is neither camelCase nor snake_case`,
      suggestion: `Rename to ${camelToSnake(field.name)} or use @map()`,
    };
  }

  // If field is camelCase and multi-word, it should have @map for snake_case in DB
  if (isCamelCase(field.name) && field.name.length > 2 && field.name !== field.name.toLowerCase()) {
    if (!field.hasMap) {
      const expected = camelToSnake(field.name);
      return {
        severity: 'info',
        category: 'naming',
        model,
        field: field.name,
        message: `camelCase field "${field.name}" lacks @map("${expected}")`,
        suggestion: `Add @map("${expected}") for explicit DB column naming`,
      };
    }
  }

  return null;
}

// ─── Index Analysis ──────────────────────────────────────────────────

/** Known fields that commonly need indices for query performance. */
const COMMONLY_INDEXED_FIELDS = [
  'userId', 'user_id', 'projectId', 'project_id',
  'status', 'createdAt', 'created_at', 'email',
  'type', 'eventType', 'event_type',
];

/**
 * Check if a model has expected indices on commonly queried fields.
 */
export function checkMissingIndices(model: SchemaModel): AuditIssue[] {
  const issues: AuditIssue[] = [];
  const indexedFields = new Set(model.indices.flatMap((idx) => idx.fields));

  for (const field of model.fields) {
    if (field.isId || field.isUnique || field.isRelation) continue;

    if (COMMONLY_INDEXED_FIELDS.includes(field.name) && !indexedFields.has(field.name)) {
      issues.push({
        severity: 'warning',
        category: 'index',
        model: model.name,
        field: field.name,
        message: `Commonly queried field "${field.name}" lacks an index`,
        suggestion: `Add @@index([${field.name}]) to model ${model.name}`,
      });
    }
  }

  return issues;
}

// ─── Timestamp Analysis ──────────────────────────────────────────────

/** Models that are typically system/auth tables and don't need timestamps */
const SYSTEM_MODEL_PREFIXES = ['schema_migrations', 'mfa_', 'sso_', 'saml_', 'oauth_'];

/**
 * Check if a model is missing standard timestamp fields.
 */
export function checkTimestamps(model: SchemaModel): AuditIssue[] {
  const issues: AuditIssue[] = [];

  // Skip system/auth models
  if (model.schema === 'auth') return issues;
  if (SYSTEM_MODEL_PREFIXES.some((p) => model.name.startsWith(p))) return issues;

  if (!model.hasCreatedAt) {
    issues.push({
      severity: 'info',
      category: 'timestamps',
      model: model.name,
      field: null,
      message: 'Model lacks createdAt/created_at field',
      suggestion: 'Add createdAt DateTime @default(now()) @map("created_at")',
    });
  }

  if (!model.hasUpdatedAt) {
    issues.push({
      severity: 'info',
      category: 'timestamps',
      model: model.name,
      field: null,
      message: 'Model lacks updatedAt/updated_at field',
      suggestion: 'Add updatedAt DateTime @updatedAt @map("updated_at")',
    });
  }

  return issues;
}

// ─── Default Value Analysis ──────────────────────────────────────────

/**
 * Fields that should typically have default values.
 */
export function checkDefaults(model: SchemaModel): AuditIssue[] {
  const issues: AuditIssue[] = [];

  for (const field of model.fields) {
    if (field.isRelation || field.isId || field.isOptional) continue;

    // Boolean fields should have defaults
    if (field.type === 'Boolean' && !field.hasDefault) {
      issues.push({
        severity: 'warning',
        category: 'defaults',
        model: model.name,
        field: field.name,
        message: `Boolean field "${field.name}" lacks a @default value`,
        suggestion: `Add @default(false) or @default(true) to "${field.name}"`,
      });
    }

    // Int fields named "count" or "total" should have defaults
    if (field.type === 'Int' && !field.hasDefault) {
      if (/count|total|retries|attempts|deliveries/i.test(field.name)) {
        issues.push({
          severity: 'info',
          category: 'defaults',
          model: model.name,
          field: field.name,
          message: `Counter field "${field.name}" lacks a @default(0)`,
          suggestion: `Add @default(0) to "${field.name}"`,
        });
      }
    }
  }

  return issues;
}

// ─── Migration Analysis ─────────────────────────────────────────────

export interface MigrationInfo {
  name: string;
  timestamp: string;
  hasDown: boolean;
}

/**
 * Parse migration directory names to extract info.
 */
export function parseMigrationNames(dirNames: string[]): MigrationInfo[] {
  return dirNames
    .filter((d) => d !== '.' && d !== '..' && d !== 'migration_lock.toml')
    .map((d) => {
      const tsMatch = d.match(/^(\d+)/);
      return {
        name: d,
        timestamp: tsMatch ? tsMatch[1] : '',
        hasDown: false, // Prisma doesn't generate down migrations by default
      };
    })
    .sort((a, b) => a.timestamp.localeCompare(b.timestamp));
}

/**
 * Check for potential migration drift indicators.
 */
export function checkMigrationHealth(
  migrations: MigrationInfo[],
  modelCount: number,
): AuditIssue[] {
  const issues: AuditIssue[] = [];

  if (migrations.length === 0) {
    issues.push({
      severity: 'error',
      category: 'migrations',
      model: '_schema',
      field: null,
      message: 'No migrations found — schema may not be synchronized',
      suggestion: 'Run `npx prisma migrate dev` to create initial migration',
    });
  }

  // Check if there's a large gap between migrations (potential drift)
  if (migrations.length >= 2) {
    const timestamps = migrations.map((m) => m.timestamp).filter(Boolean);
    if (timestamps.length >= 2) {
      const latest = timestamps[timestamps.length - 1];
      const previous = timestamps[timestamps.length - 2];
      // Check if timestamps differ by more than 30 days (format: YYYYMMDDHHMMSS or YYYYMMDD_description)
      if (latest.slice(0, 8) !== previous.slice(0, 8)) {
        const latestDate = parseTimestamp(latest);
        const previousDate = parseTimestamp(previous);
        if (latestDate && previousDate) {
          const daysDiff = (latestDate.getTime() - previousDate.getTime()) / (1000 * 60 * 60 * 24);
          if (daysDiff > 90) {
            issues.push({
              severity: 'info',
              category: 'migrations',
              model: '_schema',
              field: null,
              message: `Large gap between migrations: ${Math.round(daysDiff)} days`,
              suggestion: 'Verify schema is in sync with database. Run `npx prisma migrate status`',
            });
          }
        }
      }
    }
  }

  // Low migration-to-model ratio
  if (modelCount > 0 && migrations.length > 0) {
    const ratio = migrations.length / modelCount;
    if (ratio < 0.05 && modelCount > 20) {
      issues.push({
        severity: 'warning',
        category: 'migrations',
        model: '_schema',
        field: null,
        message: `Low migration count (${migrations.length}) relative to models (${modelCount})`,
        suggestion: 'Many schema changes may not have corresponding migrations. Review with `prisma migrate status`',
      });
    }
  }

  return issues;
}

/**
 * Parse a timestamp string like "20251011024518" into a Date.
 */
export function parseTimestamp(ts: string): Date | null {
  if (ts.length < 8) return null;
  const year = parseInt(ts.slice(0, 4), 10);
  const month = parseInt(ts.slice(4, 6), 10) - 1;
  const day = parseInt(ts.slice(6, 8), 10);
  if (isNaN(year) || isNaN(month) || isNaN(day)) return null;
  return new Date(year, month, day);
}

// ─── Report Generation ───────────────────────────────────────────────

/**
 * Run all audit checks and generate a full report.
 */
export function generateAuditReport(
  schemaContent: string,
  migrationDirs: string[],
  schemaFile: string = 'prisma/schema.prisma',
): AuditReport {
  const { models, enums } = parseSchema(schemaContent);
  const migrations = parseMigrationNames(migrationDirs);

  const issues: AuditIssue[] = [];

  // Per-model checks
  for (const model of models) {
    // Field naming checks
    for (const field of model.fields) {
      const namingIssue = checkFieldNaming(model.name, field);
      if (namingIssue) issues.push(namingIssue);
    }

    // Index checks
    issues.push(...checkMissingIndices(model));

    // Timestamp checks
    issues.push(...checkTimestamps(model));

    // Default value checks
    issues.push(...checkDefaults(model));
  }

  // Migration health
  issues.push(...checkMigrationHealth(migrations, models.length));

  // Build summary
  const publicModels = models.filter((m) => m.schema === 'public');
  const authModels = models.filter((m) => m.schema === 'auth');
  const schemas = [...new Set(models.map((m) => m.schema))];

  const summary: AuditSummary = {
    totalModels: models.length,
    totalFields: models.reduce((sum, m) => sum + m.fields.length, 0),
    totalEnums: enums.length,
    totalIndices: models.reduce((sum, m) => sum + m.indices.length, 0),
    totalIssues: issues.length,
    errorCount: issues.filter((i) => i.severity === 'error').length,
    warningCount: issues.filter((i) => i.severity === 'warning').length,
    infoCount: issues.filter((i) => i.severity === 'info').length,
    schemas,
    modelsWithoutTimestamps: publicModels
      .filter((m) => !m.hasCreatedAt || !m.hasUpdatedAt)
      .map((m) => m.name),
    modelsWithoutIndices: [...publicModels, ...authModels]
      .filter((m) => m.indices.length === 0 && m.fields.length > 2)
      .map((m) => m.name),
    namingViolations: issues.filter((i) => i.category === 'naming').length,
  };

  return {
    generatedAt: new Date().toISOString(),
    schemaFile,
    summary,
    issues,
    models,
    enums,
  };
}

/**
 * Format an audit report as human-readable text.
 */
export function formatReportText(report: AuditReport): string {
  const lines: string[] = [];

  lines.push('═══════════════════════════════════════════════════════');
  lines.push('  PRISMA SCHEMA AUDIT REPORT');
  lines.push(`  Generated: ${report.generatedAt}`);
  lines.push(`  Schema: ${report.schemaFile}`);
  lines.push('═══════════════════════════════════════════════════════');
  lines.push('');

  // Summary
  lines.push('📊 SUMMARY');
  lines.push(`  Models: ${report.summary.totalModels}`);
  lines.push(`  Fields: ${report.summary.totalFields}`);
  lines.push(`  Enums: ${report.summary.totalEnums}`);
  lines.push(`  Indices: ${report.summary.totalIndices}`);
  lines.push(`  Schemas: ${report.summary.schemas.join(', ')}`);
  lines.push('');

  // Issues
  const { errorCount, warningCount, infoCount } = report.summary;
  lines.push(`🔍 ISSUES (${report.summary.totalIssues} total)`);
  lines.push(`  ❌ Errors: ${errorCount}`);
  lines.push(`  ⚠️  Warnings: ${warningCount}`);
  lines.push(`  ℹ️  Info: ${infoCount}`);
  lines.push('');

  // Group issues by category
  const categories = [...new Set(report.issues.map((i) => i.category))];
  for (const cat of categories) {
    const catIssues = report.issues.filter((i) => i.category === cat);
    lines.push(`── ${cat.toUpperCase()} (${catIssues.length}) ──`);
    for (const issue of catIssues) {
      const icon = issue.severity === 'error' ? '❌' : issue.severity === 'warning' ? '⚠️' : 'ℹ️';
      const location = issue.field ? `${issue.model}.${issue.field}` : issue.model;
      lines.push(`  ${icon} [${location}] ${issue.message}`);
      lines.push(`     → ${issue.suggestion}`);
    }
    lines.push('');
  }

  // Models without timestamps
  if (report.summary.modelsWithoutTimestamps.length > 0) {
    lines.push('📅 MODELS WITHOUT TIMESTAMPS');
    for (const m of report.summary.modelsWithoutTimestamps) {
      lines.push(`  - ${m}`);
    }
    lines.push('');
  }

  // Models without indices
  if (report.summary.modelsWithoutIndices.length > 0) {
    lines.push('🔎 MODELS WITHOUT INDICES (with >2 fields)');
    for (const m of report.summary.modelsWithoutIndices) {
      lines.push(`  - ${m}`);
    }
    lines.push('');
  }

  // Health score
  const score = computeHealthScore(report);
  lines.push(`🏥 SCHEMA HEALTH SCORE: ${score}/100`);
  lines.push(score >= 80 ? '  ✅ Schema is in good shape' : score >= 50 ? '  ⚠️ Schema needs attention' : '  ❌ Schema has significant issues');
  lines.push('');

  return lines.join('\n');
}

/**
 * Compute a 0-100 health score from the audit report.
 */
export function computeHealthScore(report: AuditReport): number {
  let score = 100;

  // Deduct points per issue type
  score -= report.summary.errorCount * 10;
  score -= report.summary.warningCount * 3;
  score -= report.summary.infoCount * 1;

  // Bonus for having indices
  const modelCount = report.summary.totalModels;
  if (modelCount > 0) {
    const indexedRatio = 1 - report.summary.modelsWithoutIndices.length / modelCount;
    score += Math.round(indexedRatio * 5);
  }

  return Math.max(0, Math.min(100, score));
}
